const express = require('express');
const mongoose = require('mongoose');
const app = express();
app.use(express.json());

// Connect to MongoDB
mongoose.connect('mongodb://localhost:27017/mydatabase', { useNewUrlParser: true, useUnifiedTopology: true });

// Define a sample schema and model
const userSchema = new mongoose.Schema({
  name: String,
  age: Number,
  email: String
});
const User = mongoose.model('User', userSchema);

// Middleware to validate search filters
function validateFilters(filters) {
  const allowedOperators = ['$gt', '$lt', '$regex'];
  for (let key in filters) {
    if (!allowedOperators.includes(key)) {
      throw new Error('Invalid operator');
    }
    if (typeof filters[key] !== 'object' || filters[key] === null) {
      throw new Error('Invalid filter value');
    }
  }
}

// API endpoint to query users
app.post('/query', async (req, res) => {
  try {
    const filters = req.body;
    validateFilters(filters);

    const results = await User.find(filters);
    res.json(results);
  } catch (error) {
    res.status(400).json({ error: error.message });
  }
});

// Start the server
app.listen(3000, () => {
  console.log('Server is running on port 3000');
});